import{_ as e,o as r,c as a,ag as d}from"./chunks/framework.CAXxHpAX.js";const f=JSON.parse('{"title":"事实核查与来源","description":"","frontmatter":{},"headers":[],"relativePath":"sources.md","filePath":"sources.md"}'),o={name:"sources.md"};function s(c,t,l,h,i,n){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="事实核查与来源" tabindex="-1">事实核查与来源 <a class="header-anchor" href="#事实核查与来源" aria-label="Permalink to &quot;事实核查与来源&quot;">​</a></h1><p>这本书的技术判断分为三类：</p><ul><li>官方事实：来自数据库、框架或项目官方文档。</li><li>编辑判断：基于系统设计经验的解释和取舍。</li><li>待核查内容：后续出版级精修时必须补证据或降级表述。</li></ul><h2 id="当前来源矩阵" tabindex="-1">当前来源矩阵 <a class="header-anchor" href="#当前来源矩阵" aria-label="Permalink to &quot;当前来源矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>优先来源</th><th>用途</th></tr></thead><tbody><tr><td>PostgreSQL</td><td><a href="https://www.postgresql.org/docs/" target="_blank" rel="noreferrer">https://www.postgresql.org/docs/</a></td><td>分区、索引、物化视图、逻辑复制、事务</td></tr><tr><td>VitePress</td><td><a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></td><td>在线阅读站点、导航、Markdown、构建</td></tr><tr><td>Kafka</td><td><a href="https://kafka.apache.org/documentation/" target="_blank" rel="noreferrer">https://kafka.apache.org/documentation/</a></td><td>Topic、Partition、Offset、Connect、语义</td></tr><tr><td>Flink</td><td><a href="https://nightlies.apache.org/flink/flink-docs-stable/" target="_blank" rel="noreferrer">https://nightlies.apache.org/flink/flink-docs-stable/</a></td><td>Event Time、Watermark、State、Checkpoint</td></tr><tr><td>ClickHouse</td><td><a href="https://clickhouse.com/docs/" target="_blank" rel="noreferrer">https://clickhouse.com/docs/</a></td><td>MergeTree、列式存储、物化视图</td></tr><tr><td>Apache Doris</td><td><a href="https://doris.apache.org/docs/" target="_blank" rel="noreferrer">https://doris.apache.org/docs/</a></td><td>FE/BE、表模型、实时数仓</td></tr><tr><td>DuckDB</td><td><a href="https://duckdb.org/docs/" target="_blank" rel="noreferrer">https://duckdb.org/docs/</a></td><td>本地 OLAP、Parquet 查询</td></tr><tr><td>Apache Iceberg</td><td><a href="https://iceberg.apache.org/docs/" target="_blank" rel="noreferrer">https://iceberg.apache.org/docs/</a></td><td>表格式、快照、分区演化</td></tr><tr><td>pgvector</td><td><a href="https://github.com/pgvector/pgvector" target="_blank" rel="noreferrer">https://github.com/pgvector/pgvector</a></td><td>PostgreSQL 向量扩展能力</td></tr><tr><td>Milvus</td><td><a href="https://milvus.io/docs" target="_blank" rel="noreferrer">https://milvus.io/docs</a></td><td>向量数据库、索引、检索</td></tr><tr><td>Qdrant</td><td><a href="https://qdrant.tech/documentation/" target="_blank" rel="noreferrer">https://qdrant.tech/documentation/</a></td><td>向量数据库、过滤和检索</td></tr><tr><td>Neo4j</td><td><a href="https://neo4j.com/docs/" target="_blank" rel="noreferrer">https://neo4j.com/docs/</a></td><td>图数据库和 Cypher</td></tr></tbody></table><h2 id="精修要求" tabindex="-1">精修要求 <a class="header-anchor" href="#精修要求" aria-label="Permalink to &quot;精修要求&quot;">​</a></h2><ul><li>强事实必须能落到官方文档或项目文档。</li><li>产品定位类表述优先写成“适合/常见用于”，避免绝对化。</li><li>Exactly Once、事务、CDC、湖仓表格式等高误解概念必须单独核查。</li><li>每轮出版级精修都要更新本页。</li></ul><h2 id="待核查清单" tabindex="-1">待核查清单 <a class="header-anchor" href="#待核查清单" aria-label="Permalink to &quot;待核查清单&quot;">​</a></h2><p>完整待核查条目维护在仓库文档 <code>docs/fact-check-matrix.md</code>。</p><p>当前在线版本的来源矩阵表示“优先查证来源”，不表示所有章节事实已经逐条核查完成。出版级交付前，必须完成 PostgreSQL、Kafka、Flink、ClickHouse、Doris、DuckDB、Iceberg、pgvector、Milvus、Qdrant、Neo4j 等高风险技术判断的逐条核查。</p>',10)])])}const g=e(o,[["render",s]]);export{f as __pageData,g as default};
